body { font-family: "Georgia", serif; color: var(--fg); margin: 0; background: var(--card); display: grid; justify-items: center; align-items: center; padding: 12px; }
.main-wrapper{ display:flex; align-items:flex-start; gap:24px; width:100%; max-width:1200px; }
.storybook-container { position: relative; width: min(100%, 850px); background: var(--card); border-radius: var(--radius); display: flex; flex-direction: column; }
.controls-container{ background: var(--card); border-radius: var(--radius); padding: 24px; width: 220px; display: flex; flex-direction: column; align-items: center; gap: 16px; text-align: center; position: sticky; top: 12px; height: fit-content; }
.brand img { width: 150px; max-width: 100%; height: auto; display: block; margin: 0 auto; }
.page-indicator{font-size:1.425rem; color:#7a6e5c; white-space:nowrap;}
.btn{ appearance:none; border:none; border-radius:999px; padding:12px 20px; background:var(--accent); color:#fff; font-weight:600; cursor:pointer; box-shadow:0 4px 12px rgba(46,111,108,.2); font-size: 1.5rem; font-family: sans-serif; }
.scene-wrapper{ flex-grow:1; overflow: visible; padding: 32px 24px 12px; }
.scene{ display:none; max-width: 800px; margin: 0 auto; }
.scene.active{display:block;}
.art{ display: block; width: 100%; border-radius: 14px; box-shadow: 0 8px 20px rgba(0,0,0,.1); aspect-ratio: 1 / 1; object-fit: cover; }
.text-content{ height: 30rem; display: flex; flex-direction: column; justify-content: flex-end; margin-bottom: 40px; }
.vocab-page .text-content { justify-content: center; }
.title{ font-size: clamp(3.24rem, 9vw, 5.22rem); text-align:center; margin: 8px 0 0 0; text-wrap:balance; }
.para{ font-size: clamp(2.6rem, 8vw, 3.8rem); line-height:1.4; margin:0; text-align:center; text-wrap:pretty; }
.para-translation{ font-family: sans-serif; font-size: clamp(1.59rem, 4.63vw, 2.12rem); line-height: 1.6; color: #000; margin: 0 0 12px 0; text-align: center; text-wrap: pretty; }
audio{position:absolute; width:0; height:0; opacity:0;}
@media (max-width: 960px){ .main-wrapper{flex-direction:column;} .controls-container{width:100%; position:static;} .page-indicator{white-space:normal;} .text-content{ height: auto; min-height: auto; } }
.logo-container { position: absolute; bottom: 16px; right: 16px; z-index: 10; }
.brand-logo-story { width: 100px; height: auto; display: block; filter: drop-shadow(0 2px 4px rgba(0,0,0,0.3)); }
