<script>
document.addEventListener('DOMContentLoaded', () => {
let currentPage = 1;
let totalPages = 0;
let isAutoplaying = false;
let isFinished = false;
let noAudioTimer = null;
const playBtn = document.getElementById('play-pause');
const pageIndicator = document.getElementById('page-indicator');
const scenes = document.querySelectorAll('.scene');

const sceneEl = n => document.getElementById('page-' + n);
const currentAudio = () => { const s = sceneEl(currentPage); return s ? s.querySelector('audio') : null; };

function setPage(n) {
if (n < 1 || n > totalPages) return;
pauseCurrentAudio();
const oldScene = sceneEl(currentPage);
if (oldScene) oldScene.classList.remove('active');
currentPage = n;
isFinished = (currentPage === totalPages);
const newScene = sceneEl(currentPage);
if (newScene) newScene.classList.add('active');
updateUI();
if (isAutoplaying) playCurrentAudio();
}

function playCurrentAudio() {
const audio = currentAudio();
if (audio) {
audio.play().catch(e => {
console.error(e);
if (isAutoplaying) noAudioTimer = setTimeout(nextPage, 2000);
});
} else {
if (isAutoplaying) noAudioTimer = setTimeout(nextPage, 2000);
}
}

function pauseCurrentAudio() {
const audio = currentAudio();
if (audio && !audio.paused) { audio.pause(); audio.currentTime = 0; }
if (noAudioTimer) { clearTimeout(noAudioTimer); noAudioTimer = null; }
}

function toggleAutoplay() {
if (isFinished) { isFinished = false; isAutoplaying = true; setPage(1); return; }
isAutoplaying = !isAutoplaying;
if (isAutoplaying) playCurrentAudio(); else pauseCurrentAudio();
updateUI();
}

function nextPage() {
if (currentPage < totalPages) setPage(currentPage + 1);
else if (isAutoplaying) { isFinished = true; isAutoplaying = false; updateUI(); }
}

function prevPage() {
if (currentPage > 1) { if(isAutoplaying) isAutoplaying = false; setPage(currentPage - 1); }
}

function updateUI() {
pageIndicator.textContent = `Seite ${currentPage} / ${totalPages}`;
if (isFinished) { playBtn.textContent = 'Replay ↺'; playBtn.setAttribute('aria-pressed', 'false'); }
else if (isAutoplaying) { playBtn.textContent = 'Pause ⏸'; playBtn.setAttribute('aria-pressed', 'true'); }
else { playBtn.textContent = 'Play ▶'; playBtn.setAttribute('aria-pressed', 'false'); }
}

function handleKeydown(e) {
if (e.key === 'ArrowRight') nextPage();
else if (e.key === 'ArrowLeft') prevPage();
}

function initializeStorybook() {
totalPages = scenes.length;
if (totalPages === 0) { playBtn.disabled = true; return; }
scenes.forEach(scene => {
const audio = scene.querySelector('audio');
if (audio) {
audio.addEventListener('ended', () => { if (isAutoplaying) nextPage(); });
}
});
playBtn.addEventListener('click', toggleAutoplay);
document.addEventListener('keydown', handleKeydown);
setPage(1);
}

initializeStorybook();
});
</script>

</body>
