  <div class="main-wrapper">
    <div class="storybook-container" role="region" aria-label="Storybook Content">
      <div class="scene-wrapper">
          <!-- PAGE 1: COVER -->
          <div id="page-1" class="scene active">
            <audio preload="metadata" src="[Cover Audio URL]" aria-label="Title audio"></audio>
            <div class="text-content">
              <p class="para-translation">[Chinese Title]</p>
              <h1 class="title">[Story Title]</h1>
            </div>
