              <div class="vocab-list">
                <h2 class="vocab-title">[Vocabulary Title]</h2>
                <p class="para-translation" style="margin-bottom: 24px;">重要词汇</p>
                <!-- VOCAB ENTRIES WILL BE DYNAMICALLY INSERTED HERE -->
                <!-- e.g. <p class="vocab-entry"><strong>geduldig</strong> — <span class="vocab-translation">耐心</span></p> -->
              </div>
            </div>
          </div>
      </div>
    </div>
    <div class="controls-container" role="region" aria-label="Storybook Controls">
        <div class="brand"><img src="http://192.168.2.34:29695/rest/files/images/eec227eb-305c-4731-933a-5de5d81feb5a.png" alt="Brand Logo"/></div>
        <div class="page-indicator" id="page-indicator">Seite 1 / [Total Pages]</div>
        <button id="play-pause" class="btn" aria-pressed="false" aria-label="Play oder Pause">Play ▶</button>
        <div style="font-size:1.275rem; color:#6e6250; font-family: sans-serif;">Tasten: ←/→ wechseln</div>
    </div>
  </div>

  <script>
    document.addEventListener('DOMContentLoaded', () => {
      // --- STATE ---
      let currentPage = 1;
      let totalPages = 0; // This will be updated
      let isAutoplaying = false;
      let isFinished = false;
      let noAudioTimer = null;

      // --- ELEMENTS ---
      const playBtn = document.getElementById('play-pause');
      const pageIndicator = document.getElementById('page-indicator');
      const scenes = document.querySelectorAll('.scene');

      // --- HELPERS ---
      const sceneEl = n => document.getElementById('page-' + n);
      const currentAudio = () => {
        const s = sceneEl(currentPage);
        return s ? s.querySelector('audio') : null;
      };

      /**
       * Sets the current visible page and updates the story state.
       * @param {number} n - The page number to display.
       */
      function setPage(n) {
        if (n < 1 || n > totalPages) return;

        pauseCurrentAudio();

        const oldScene = sceneEl(currentPage);
        if (oldScene) oldScene.classList.remove('active');

        currentPage = n;
        isFinished = (currentPage === totalPages);

        const newScene = sceneEl(currentPage);
        if (newScene) newScene.classList.add('active');

        updateUI();

        if (isAutoplaying) {
          playCurrentAudio();
        }
      }

      /**
       * Plays the audio for the current page.
       */
      function playCurrentAudio() {
        const audio = currentAudio();
        if (audio) {
          audio.play().catch(e => {
            console.error(`Error playing audio for page ${currentPage}:`, e);
            if (isAutoplaying) {
              noAudioTimer = setTimeout(nextPage, 2000);
            }
          });
        } else {
          if (isAutoplaying) {
            noAudioTimer = setTimeout(nextPage, 2000);
          }
        }
      }

      /**
       * Pauses the currently playing audio and clears any related timers.
       */
      function pauseCurrentAudio() {
        const audio = currentAudio();
        if (audio && !audio.paused) {
          audio.pause();
          audio.currentTime = 0;
        }
        if (noAudioTimer) {
          clearTimeout(noAudioTimer);
          noAudioTimer = null;
        }
      }

      /**
       * Toggles the autoplay state. Handles play, pause, and replay.
       */
      function toggleAutoplay() {
        if (isFinished) { // Replay logic
          isFinished = false;
          isAutoplaying = true;
          setPage(1);
          return;
        }

        isAutoplaying = !isAutoplaying;

        if (isAutoplaying) {
          playCurrentAudio();
        } else {
          pauseCurrentAudio();
        }
        updateUI();
      }

      /**
       * Navigates to the next page.
       */
      function nextPage() {
        if (currentPage < totalPages) {
          setPage(currentPage + 1);
        } else if (isAutoplaying) {
          isFinished = true;
          isAutoplaying = false;
          updateUI();
        }
      }

      /**
       * Navigates to the previous page.
       */
      function prevPage() {
        if (currentPage > 1) {
          if(isAutoplaying) isAutoplaying = false; // Manual navigation stops autoplay
          setPage(currentPage - 1);
        }
      }

      /**
       * Updates all UI elements based on the current state.
       */
      function updateUI() {
        // totalPages is dynamically set in initializeStorybook
        pageIndicator.textContent = `Seite ${currentPage} / ${totalPages}`;

        if (isFinished) {
          playBtn.textContent = 'Replay ↺';
          playBtn.setAttribute('aria-pressed', 'false');
        } else if (isAutoplaying) {
          playBtn.textContent = 'Pause ⏸';
          playBtn.setAttribute('aria-pressed', 'true');
        } else {
          playBtn.textContent = 'Play ▶';
          playBtn.setAttribute('aria-pressed', 'false');
        }
      }

      /**
       * Handles keyboard events for navigation.
       * @param {KeyboardEvent} e
       */
      function handleKeydown(e) {
        if (e.key === 'ArrowRight') {
          nextPage();
        } else if (e.key === 'ArrowLeft') {
          prevPage();
        }
      }

      /**
       * Initializes the storybook functionality.
       */
      function initializeStorybook() {
        totalPages = scenes.length;
        if (totalPages === 0) {
          console.error("No scenes found.");
          playBtn.disabled = true;
          return;
        }

        scenes.forEach(scene => {
          const audio = scene.querySelector('audio');
          if (audio) {
            audio.addEventListener('ended', () => {
              if (isAutoplaying) {
                nextPage();
              }
            });
          }
        });

        playBtn.addEventListener('click', toggleAutoplay);
        document.addEventListener('keydown', handleKeydown);

        setPage(1); // Set initial state and UI
      }

      initializeStorybook();
    });
  </script>
</body>
